// Validate the caller's Supabase access token AND return their user id.
// (api-chat.ts only needed a yes/no; here we need the id to scope rows.)
async function getUser(token: string): Promise<{ id: string } | null> {
  try {
    const r = await fetch(`${SUPABASE_URL}/auth/v1/user`, {
      headers: { apikey: SUPABASE_ANON_KEY, Authorization: `Bearer ${token}` },
    });
    if (!r.ok) return null;
    const u = (await r.json()) as { id?: string };
    return u && typeof u.id === "string" ? { id: u.id } : null;
  } catch {
    return null;
  }
}

